sort(  # Using sort instead of sort_desc since lower is better now
  1 / (
    avg by (provider) (
      (
        1 / avg by (provider) (
          quantile_over_time(0.95, 
            response_latency_seconds{metric_type="response_time", blockchain="Solana", response_status="success", source_region="fra1"}[$__range]
          )
        )
      )
      *
      (
        (
          sum by (provider) (count_over_time(response_latency_seconds{metric_type="response_time", blockchain="Solana", response_status="success", source_region="fra1"}[$__range]))
          /
          sum by (provider) (count_over_time(response_latency_seconds{metric_type="response_time", blockchain="Solana", source_region="fra1"}[$__range]))
        )
        *
        (
          sum by (provider) (count_over_time(response_latency_seconds{metric_type="response_time", blockchain="Solana", response_status="success", source_region="fra1"}[$__range]))
          /
          sum by (provider) (count_over_time(response_latency_seconds{metric_type="response_time", blockchain="Solana", source_region="fra1"}[$__range]))
        )
        *
        (
          sum by (provider) (count_over_time(response_latency_seconds{metric_type="response_time", blockchain="Solana", response_status="success", source_region="fra1"}[$__range]))
          /
          sum by (provider) (count_over_time(response_latency_seconds{metric_type="response_time", blockchain="Solana", source_region="fra1"}[$__range]))
        )
      )
    )
  )
)

